class NewsBoxUpdater{constructor(e=3e5){this.getNews(),setInterval(this.getNews,e)}getNews(){if(!document.hasFocus())return;let e=document.getElementById("news-container");fetch("/api/news",{method:"GET"}).then(t=>{t.json().then(t=>{e.replaceChildren(),t.data.forEach(t=>{let n=document.createElement("li"),a=document.createElement("a"),o=document.createElement("h6");a.href=`/news/${t.id}`,a.innerText=t.title,o.textContent=`(${luxon.DateTime.fromISO(t.created_at).toRelativeCalendar()})`,twemoji.parse(a),n.appendChild(a),n.appendChild(o),e.appendChild(n)})})})}}class TagsBoxUpdater{constructor(){this.getTags()}getTags(){let e=document.getElementById("tag-container");fetch("/api/tags?sort=post_count&order=desc").then(t=>{t.json().then(t=>{t.data.forEach(t=>{if(t.post_count>0&&"banned"!=t.type){var n=document.createElement("li"),a=document.createElement("p"),o=document.createElement("div");a.href=`/posts/?tags=${t.name}`,a.innerText=t.humanized,o.innerText=Humanize.compactInteger(t.post_count,1),n.classList.add(t.type),n.appendChild(a),n.appendChild(o),n.onclick=()=>{location.href=`/posts/?tags=${t.name}`},n.title=t.description,e.appendChild(n)}})})})}}export{NewsBoxUpdater,TagsBoxUpdater};